"""
MKT Original Commentary — Joshua chapters 12–14
Run: python3 scripts/zc-original-joshua-12-14.py

Source data used:
- data/interlinear/joshua.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/joshua.json

Key decisions in this range:
- ch12: king-list chapter treated with brief philological notes on key terms
  (Rephaim, the 31-king total, ḥērem summary vocabulary)
- ch13: mille' aḥărê YHWH ('wholeheartedly follow') rendered consistently;
  Levi's inheritance formula (YHWH is their naḥălāh) is a key theological motif
- ch14: Caleb's 'wholehearted' formula (mille' aḥărê) appears 3× in vv.8,9,14 —
  the Hebrew mille' lit. 'filled after' is distinctive and traced throughout
- Balaam in 13:22 is called qōsēm ('diviner/sorcerer') — contrasted with nābîʾ
  ('prophet'); the distinction matters for how his death is narrated
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

JOSHUA = {
  "12": {
    # Chapter 12 is a victory inventory — 31 kings east and west of the Jordan.
    # The theological function: a comprehensive list that closes the conquest narrative
    # and frames the allotment chapters that follow.
    "1": "<p><em>wĕʾēlleh malkê hāʾāreṣ ʾašer hikkû bĕnê yiśrāʾēl</em> — 'these are the kings of the land that the Israelites struck.' The list form (king-roster) is a known genre in ANE victory texts; Assyrian and Egyptian annals feature comparable king-lists. Its function here is theological: the God who promised Abraham this land (Gen 15:18-21) has delivered 31 rulers, beginning with the two trans-Jordan paradigm cases (Sihon and Og) established in Numbers 21.</p>",
    "2": "<p>Sihon king of the Amorites is first — his defeat (Num 21:21-31) was the breakthrough moment that silenced Israel's objection to crossing into Canaan. <em>yōšēb bĕḥešbôn mōšēl mēʿărôʿēr</em> — 'who lived in Heshbon, who ruled from Aroer.' The geographic precision (Arnon River, Jabbok River, half of Gilead) is an official boundary description, the language of land grants. The Mosaic victories function as the legal precedent for the Canaanite allotments.</p>",
    "3": "<p>The eastern Arabah — from Kinnereth (Sea of Galilee) to the Salt Sea (Dead Sea). <em>ûmimmizraḥ haʿărābāh</em> covers the full Jordan rift valley under Sihon's control. This eastern survey is the legal background for ch.13's trans-Jordan allotments; the boundaries here are not narrative decoration but the formal basis for tribal land titles.</p>",
    "4": "<p>Og of Bashan: <em>min-yeter hārĕpāʾîm</em> — 'one of the last of the Rephaim.' The Rephaim were the giant peoples of the pre-Israelite Canaan (Gen 14:5; 15:20; Deut 2:20-21; 3:11). Og's famous iron bed (Deut 3:11) measured 9 cubits × 4 cubits — whether a bed or a sarcophagus, it was preserved as a monument to the victory. His territory reached to Hermon; the defeat of this last Rephaite king is the culmination of a campaign against supernatural-sized opponents that began in the wilderness.</p>",
    "5": "<p>Og's territory: Mount Hermon, Salecah, all of Bashan. The border with the Geshurites and Maacathites is significant: these peoples are not driven out (Josh 13:13), and Geshur will later be David's maternal homeland (2 Sam 3:3) — political geography and later narrative are already entangled in this boundary description.</p>",
    "6": "<p><em>mōšeh ʿebed YHWH ûbĕnê yiśrāʾēl hikkûm</em> — 'Moses the servant of the LORD and the Israelites struck them.' Sihon and Og are assigned to Moses; the trans-Jordan victories are Mosaic inheritance. <em>wayyittĕnāh mōšeh yerûššāh</em> — 'Moses gave it as a possession.' <em>Yerûššāh</em> (possession, inherited property) is legally stronger than mere conquest; the trans-Jordan tribes hold by Mosaic grant, not just military occupation.</p>",
    "7": "<p>The Cisjordan list begins: <em>wĕʾēlleh malkê hāʾāreṣ ʾašer hikkāh yĕhôšuaʿ ûbĕnê yiśrāʾēl</em>. The parallel structure (Mosaic victories / Josuaic victories) is deliberate: Joshua completes what Moses began. The geographic frame — Baal-gad in the Lebanon Valley to Mount Halak in the south — defines the full conquest zone announced in ch.1:4.</p>",
    "8": "<p>The land's varied terrain is listed: hill country, western foothills (<em>šĕpēlāh</em>), the Arabah, mountain slopes (<em>ʾăšēdôt</em>), wilderness, and Negev. These six zones correspond to the campaign zones of chs.10-11. The six peoples list (Hittites, Amorites, Canaanites, Perizzites, Hivites, Jebusites) is the standard Deuteronomic enumeration (Deut 7:1) — the list signals that YHWH's mandate to dispossess these specific peoples has been carried out.</p>",
    "9": "<p>The Cisjordan list proper begins: king of Jericho (one), king of Ai (one). The formulaic <em>melek ... ʾeḥād</em> ('king of X, one') is the signature structure of the list. Starting with Jericho and Ai grounds the list in the paradigmatic first two victories of chs.6-8; every subsequent entry is measured against those standards.</p>",
    "10": "<p>Jerusalem and Hebron. Jerusalem's king Adonizedek was defeated in ch.10 but the city itself was not yet taken (Josh 15:63; Judg 1:21 — it remains Jebusite until David). Hebron will become Caleb's inheritance (ch.14) and later David's first capital. The list includes the king as the defeated party; city occupation is a separate question.</p>",
    "11": "<p>Jarmuth, Lachish — part of the southern coalition defeated in ch.10. Lachish appears in later Assyrian records (the Lachish Reliefs of Sennacherib, ANET 287-288) as one of Judah's strongest fortresses; its prominence in the conquest list reflects its genuine strategic importance.</p>",
    "12": "<p>Eglon, Gezer. Gezer's king Horam was defeated (ch.10:33) but Gezer itself was not fully taken (Josh 16:10: 'the Canaanites who lived in Gezer were not driven out'). The list records the king's defeat, not necessarily the city's complete occupation — a distinction the allotment chapters will clarify.</p>",
    "13": "<p>Debir, Geder. Debir's double appearance (here; ch.15:15-17 as Othniel's conquest) reflects either a reconquest after Canaanite resettlement or variant traditions preserved side by side. The list does not attempt to resolve this; it records the Joshua-era defeat.</p>",
    "14": "<p>Hormah (<em>ḥormāh</em>, from <em>ḥērem</em>, 'devoted to destruction') — the name itself encodes the <em>ḥērem</em> ideology; its place-name likely commemorates an earlier battle (Num 14:45; 21:3). Arad — the Negev fortress whose king also attacked Israel in Num 21:1-3.</p>",
    "15": "<p>Libnah, Adullam — both in the Shephelah. Adullam will become famous as David's cave-refuge (1 Sam 22:1), setting up a future narrative connection already embedded in the geography of conquest.</p>",
    "16": "<p>Makkedah, Bethel. Bethel's prominence in patriarchal narrative (Gen 12:8; 28:19 — where Jacob named it 'house of God') gives its appearance in the conquest list theological weight: the place where YHWH promised Abraham and Jacob the land is now taken.</p>",
    "17": "<p>Tappuah, Hepher. Geographic completeness: the list is cataloguing the western foothills and northern Shephelah, ensuring no gap in the victory record.</p>",
    "18": "<p>Aphek, Lasharon. Aphek will be significant later: it is the Philistine staging ground when the ark is captured (1 Sam 4:1) — conquest-era and monarchic-era narratives share geography.</p>",
    "19": "<p>Madon, Hazor. Hazor is the last of the major northern cities listed (the one Joshua burned, ch.11:11); its appearance in this comprehensive list anchors the northern campaign's climax in the victory inventory.</p>",
    "20": "<p>Shimron-meron, Achshaph — northern Galilean cities of the Jabin coalition (ch.11:1). Their inclusion confirms the list's geographic sweep: south to north, every major coalition city enumerated.</p>",
    "21": "<p>Taanach, Megiddo — the great northern fortress cities controlling the Jezreel Valley passes. Megiddo (later <em>har Megiddon</em> = Armageddon, Rev 16:16) was not fully taken — Judg 1:27 notes Manasseh failed to drive out Taanach and Megiddo's Canaanites. The gap between the list's claim and later reality is intentional: the list asserts the kings' defeat, not permanent occupation.</p>",
    "22": "<p>Kedesh, Jokneam in Carmel — the Galilean hill country and the ridge leading to the coast. These are the northernmost cities in the Cisjordan list, completing the geographic arc from Jericho (v.9) in the south to Galilee in the north.</p>",
    "23": "<p>Dor in the Naphoth-dor coastal plain, Goiim in Gilgal — filling out the Mediterranean coast. The inclusion of coastal cities alongside the inland cities marks the scope as truly comprehensive, even as subsequent chapters acknowledge Canaanite persistence in many of these areas.</p>",
    "24": "<p><em>kol-mĕlākîm šĕlōšîm wĕʾeḥād</em> — 'all the kings, thirty-one.' The number closes the list with deliberate finality. Thirty-one defeated kings document total YHWH-given victory across every region of Canaan. The number itself is not mystically significant, but its precision as a closed inventory signals that the conquest narrative is complete: all that needed to be said about conquest has been said; what follows (chs.13-22) is inheritance distribution.</p>"
  },
  "13": {
    "1": "<p><em>wîhôšuaʿ zāqēn bāʾ bayyāmîm</em> — 'Joshua was old, advanced in days.' The idiom <em>bāʾ bayyāmîm</em> ('come into days') appears elsewhere only of Abraham (Gen 24:1) and David (1 Kgs 1:1); it signals a leader at the end of his productive season. YHWH's immediate response — 'much land remains to be possessed' — frames the problem: the conquest is unfinished, and the leader is aging. The tension between incomplete possession and approaching death drives chapters 13-24.</p>",
    "2": "<p><em>zōʾt hāʾāreṣ hanniśʾāret</em> — 'this is the land that remains.' The admission that land remains contradicts the conquest summaries of 11:23 and 21:43 only if those summaries are taken as absolute rather than judicial. The ideal ('all the land was taken') and the realistic ('land remains') coexist — the former is a theological verdict on YHWH's faithfulness; the latter is a historical acknowledgment of incomplete execution.</p>",
    "3": "<p>The Philistine pentapolis: Gaza, Ashdod, Ashkelon, Gath, Ekron. <em>hammiṣraʾ ʾašer ʿal-pĕnê miṣrayim</em> — 'the Shihor, which is before Egypt' — marks the southwestern boundary. The Philistine cities are counted as Canaanite territory (<em>liknāʿanî teḥāšēb</em>) — a legal categorization that will later matter for how their continued occupation is understood.</p>",
    "4": "<p>Southward: Canaanite territory and Mearah of the Sidonians. The inclusion of Sidonian territory (Phoenician coast) within the land's ideal boundaries reflects the Gen 15:18-21 promise ('from the river of Egypt to the great river, the Euphrates'). The actual possession never reached these limits; the promise remains partially unfulfilled, pointing forward to the ultimate Davidic/Solomonic expansion (1 Kgs 4:21) and beyond.</p>",
    "5": "<p>Lebanon from Baal-gad to Lebo-hamath — the northern boundaries of the ideal land. The Giblites (<em>haggĕblî</em>) are the inhabitants of Byblos (Gebal), a major Phoenician port. These northern territories remain unoccupied throughout the monarchy period; their inclusion in the 'remaining land' acknowledges the gap between promise and possession.</p>",
    "6": "<p><em>ʾănî ʾōrîšennem mippĕnê bĕnê yiśrāʾēl</em> — 'I will drive them out before Israel.' YHWH's first-person commitment — 'I will do it' — shifts responsibility back to divine action. Joshua's role is now to divide the land by lot (<em>raq happilah lĕyiśrāʾēl bĕnaḥălāh</em>); the driving out will happen as Israel obeys within its allotments. The promise structure: YHWH acts as Israel advances.</p>",
    "7": "<p><em>wĕʿattāh ḥalleq ʾet-hāʾāreṣ hazzōʾt bĕnaḥălāh</em> — 'now divide this land as inheritance.' The imperative and the noun <em>naḥălāh</em> (inheritance) together signal a major structural transition: from conquest narrative to inheritance distribution. <em>Naḥălāh</em> (appearing ~200× in the OT) denotes permanent familial patrimony — land held not by right of conquest alone but by covenantal grant, passed through generations.</p>",
    "8": "<p>Review of the trans-Jordan inheritance given by Moses. The Reubenites, Gadites, and half-tribe of Manasseh received their allotments east of the Jordan (Num 32); this chapter confirms those grants. The Mosaic inheritance is the precedent and model for the Josuaic distribution now beginning.</p>",
    "9": "<p>Trans-Jordan geography: Aroer by the Arnon, the city in the middle of the valley, the Medeba plateau. The <em>mishor</em> ('plateau/tableland') is the characteristic terrain of Moab and trans-Jordan Reuben — flat, elevated plain east of the Dead Sea. The geographic details are the property records of Reubenite land tenure.</p>",
    "10": "<p>All the cities of Sihon up to the Ammonite border. <em>ʿad-gĕbûl bĕnê ʿammôn</em> — 'to the border of the Ammonites.' The Ammonites are intentionally excluded; Deut 2:19 forbids Israel from taking Ammonite territory ('I have given it to the sons of Lot as a possession'). These land grants respect the existing distribution of peoples even as they claim Amorite territory.</p>",
    "11": "<p>Gilead, the territory of Geshurites and Maacathites, and all Mount Hermon. <em>wĕhakkol haggĕšûrî wĕhammaakatî</em> — the Geshurites and Maacathites are included in the allotment description but not in the actual possession, as v.13 will immediately note. The legal grant and the actual possession diverge; the gap is acknowledged but not resolved.</p>",
    "12": "<p><em>kol-mamleket ʿōg babbāšān ʾašer-mālaḵ bĕʿaštārôt ûbĕʾedreʿî hûʾ nišʾar miyeter hārĕpāʾîm</em> — 'the whole kingdom of Og in Bashan, who reigned at Ashtaroth and Edrei; he alone remained of the remnant of the Rephaim.' The Rephaim identification is repeated from ch.12:4, maintaining the motif: this territory was won from the last of a dying race of giant peoples. The conquest of trans-Jordan was a conquest of the uncanny as much as the military.</p>",
    "13": "<p><em>wĕlōʾ hōrîšû bĕnê yiśrāʾēl ʾet-haggĕšûrî wĕʾet-hammaʿăkātî</em> — 'the Israelites did not drive out the Geshurites or the Maacathites.' The first of the failure notices that punctuate the allotment chapters. <em>wayyēšeb haggĕšûrî wĕhammaakatî bĕqereb yiśrāʾēl ʿad hayyôm hazzeh</em> — 'they live among Israel to this day.' The 'to this day' formula marks the note as etiological — explaining a visible present reality by reference to a past decision. Geshur's survival will eventually produce Maacah, who becomes David's wife and Absalom's mother (2 Sam 3:3; 13:37) — an unconquered people becomes a dynastic entanglement.</p>",
    "14": "<p><em>raq lĕšēbeṭ halēwî lōʾ-nātan naḥălāh</em> — 'only to the tribe of Levi he did not give an inheritance.' The <em>raq</em> ('only/except') marks Levi as the single anomaly in the distribution system. <em>ʾiššê YHWH ʾĕlōhê yiśrāʾēl hûʾ naḥălātô</em> — 'the fire-offerings of YHWH God of Israel are their inheritance.' The <em>naḥălāh</em> of YHWH's fire-offerings (<em>ʾiššê</em>) replaces territory; Levi's sustenance comes from the altar, not the land. This principle — that priestly service to YHWH constitutes an inheritance — is the theological foundation for the NT principle that ministers of the gospel are supported by those they serve (1 Cor 9:13-14).</p>",
    "15": "<p>The Reubenite allotment begins. <em>wayyittēn mōšeh lĕmaṭṭēh bĕnê rĕʾûbēn lĕmišpĕḥōtām</em> — 'Moses gave to the tribe of Reuben according to their clans.' The distribution unit is the <em>mišpāḥāh</em> (clan/extended family group), not the individual; the inheritance is corporate and generational.</p>",
    "16": "<p>Reuben's territory: Aroer by the Arnon, the city in the middle of the valley, and the Medeba plateau. The precise boundary descriptions use the landmark-and-feature format of ANE boundary texts (parallel to Egyptian and Hittite treaty boundary clauses). Each named landmark is a legally recognized point in the property description.</p>",
    "17": "<p>Cities within Reuben's allotment: Heshbon (Sihon's capital), Dibon, Bamoth-baal, Beth-baal-meon. The presence of <em>baal</em>-names in the allotted territory (Beth-baal-meon, Bamoth-baal) reflects Canaanite place-names that Israel inherited without immediately renaming — the toponym preserves the religious history of the land even as it changes ownership.</p>",
    "18": "<p>Jahaz, Kedemoth, Mephaath — sites along Reuben's eastern border. Jahaz was where Sihon attacked Israel (Num 21:23; Deut 2:32), making its inclusion in Reuben's allotment a direct conversion of battlefield to farmland.</p>",
    "19": "<p>Kiriathaim, Sibmah, Zereth-shahar on the hill in the valley — Reuben's hill country. Sibmah was known for its vineyards (Isa 16:8-9; Jer 48:32) — the allotment assigns productive agricultural land, not merely boundary markers.</p>",
    "20": "<p>Beth-peor, the slopes of Pisgah, Beth-jeshimoth. Beth-peor is freighted with memory: it was at Peor that Israel committed apostasy with Moabite women (Num 25:3; Deut 4:3). Moses was buried 'in the valley opposite Beth-peor' (Deut 34:6). Reuben's inheritance includes sites of Israel's deepest failures — the land is taken in full, shame included.</p>",
    "21": "<p>All the cities of the plateau (<em>ʿārê hammiššôr</em>) and the kingdom of Sihon. The formula <em>kol-mamleket sîḥōn melek hāʾĕmōrî ʾašer mālaḵ bĕḥešbôn</em> — 'the whole kingdom of Sihon king of the Amorites who reigned at Heshbon' — signals that Reuben inherits not just territory but sovereignty: what was a Canaanite kingdom becomes an Israelite tribal holding.</p>",
    "22": "<p><em>wĕʾet-bilʿām ben-bĕʿôr haqqōsēm hārĕgû bĕnê yiśrāʾēl beḥereb</em> — 'Balaam son of Beor the diviner, the Israelites killed with the sword.' The term <em>qōsēm</em> (diviner, one who practices <em>qĕsāmôt</em>) labels Balaam by his means of knowledge, not just his role. In Num 22-24 Balaam functions as a prophet (<em>nābîʾ</em>-like figure) who speaks YHWH's words; here he is demoted to <em>qōsēm</em> — one whose methods are prohibited in Israel (Deut 18:10). The retroactive reclassification reflects his ultimate fate: a man who blessed Israel was killed as a collaborator in Midian's seduction of Israel (Num 31:8,16). The NT references to Balaam (2 Pet 2:15; Jude 11; Rev 2:14) follow this pejorative labeling.</p>",
    "23": "<p>The Jordan and its border constitute Reuben's western boundary. <em>gĕbûl bĕnê rĕʾûbēn wayyihyeh hayyardēn ûgĕbûl</em> — 'the Jordan and its bank was their border.' The Jordan is both boundary and identity marker: the trans-Jordan tribes are defined by their position east of the river, which will become a point of tension in ch.22 (the altar dispute).</p>",
    "24": "<p>The Gadite allotment begins. <em>wayyittēn mōšeh lĕmaṭṭēh gād lĕmišpĕḥōtām</em> — structural parallel to the Reubenite grant formula.</p>",
    "25": "<p>Gad's territory: Jazer, all the cities of Gilead, and half the Ammonite territory 'to Aroer which is before Rabbah.' The Ammonite adjacency makes Gad the eastern frontier tribe, bordering the perennial Ammonite opponents. Gilead's association with Gad is so strong that 'Gilead' becomes a shorthand for the trans-Jordan tribes (Judg 5:17; 10:18).</p>",
    "26": "<p>From Heshbon to Ramath-mizpeh and Betonim; from Mahanaim to the border of Debir. Mahanaim is Jacob's site of angelic encounter (Gen 32:2), where he named the place 'two camps'; it becomes an Israelite administrative and military base (2 Sam 2:8; 17:24; 1 Kgs 2:8). Jacob's patriarchal sites become Gadite cities.</p>",
    "27": "<p>In the valley: Beth-haram, Beth-nimrah, Succoth, Zaphon — these are the Jordan valley floor settlements, fertile lowlands east of the river. Succoth was Jacob's first settlement returning from Laban (Gen 33:17), another patriarchal site incorporated into the tribal map.</p>",
    "28": "<p>The Gadite inheritance concludes: cities and their villages. The total is measured against the Mosaic grant formula: <em>zōʾt naḥălat bĕnê-gād lĕmišpĕḥōtām</em> — 'this is the inheritance of the Gadites by their clans.' The clan-unit distribution ensures generational continuity.</p>",
    "29": "<p>Half-Manasseh's trans-Jordan territory. <em>wayyittēn mōšeh laḥăṣî šēbet hamnașṣeh</em> — Moses distributes to the half-tribe, reflecting the unusual division of Manasseh between trans-Jordan (half) and Cisjordan (half). This split-tribe arrangement creates structural complexity in the later allotment chapters (Josh 17) as both halves are allocated separately.</p>",
    "30": "<p>Half-Manasseh's territory from Mahanaim through all Bashan: <em>kol-baššān kol-mamleket ʿōg babbāšān wĕkol-ḥawwōt yāʾîr</em> — 'all Bashan, the whole kingdom of Og, and all the tent-villages of Jair.' The Havvoth-jair ('tent-villages of Jair') represent a form of semi-nomadic settlement, named for the Manassite hero Jair (Num 32:41) — personal-name places that encode the history of conquest in the landscape.</p>",
    "31": "<p>Half of Gilead and Og's cities (Ashtaroth and Edrei) go to half-Manasseh. <em>lĕbnê mākhîr ben-manašše laḥăṣî</em> — 'to the descendants of Machir son of Manasseh, for half of them.' Machir is the dominant Manassite clan; the allotment recognizes clan-level distinctions within the tribe.</p>",
    "32": "<p><em>ʾēlleh ʾašer niḥal mōšeh bĕʿarābōt môʾāb</em> — 'these are what Moses distributed in the plains of Moab.' The trans-Jordan distribution is retrospective: Eleazar and Joshua had not yet begun; the Cisjordan allotments are still ahead. The chapter closes the Mosaic distribution before opening Joshua's.</p>",
    "33": "<p><em>wĕlišēbeṭ halēwî lōʾ-nātan mōšeh naḥălāh</em> — 'to the tribe of Levi Moses gave no inheritance.' The Levitical exception closes the chapter and mirrors v.14. <em>YHWH ʾĕlōhê yiśrāʾēl hûʾ naḥălātām</em> — 'YHWH God of Israel is their inheritance.' The <em>hûʾ</em> ('he is') is emphatic — not just any inheritance but YHWH himself as the inalienable possession. This theological principle is picked up in Ps 16:5 ('YHWH is my chosen portion and my cup') and pervades the NT understanding of God as the believer's ultimate inheritance (Eph 1:14,18; 1 Pet 1:4).</p>"
  },
  "14": {
    "1": "<p><em>wĕʾēlleh ʾašer niḥălû bĕnê yiśrāʾēl bĕʾereṣ kĕnaʿan ʾašer niḥălû ʾōtām ʾelʿāzār hakōhēn wîhôšuaʿ bin-nûn wĕrāʾšê hāʾăbôt</em> — 'these are what the Israelites received as inheritance in the land of Canaan, which Eleazar the priest, Joshua son of Nun, and the heads of the fathers' [houses] distributed to them.' Three-party oversight: priest (covenant mediator), commander (covenantal executor), and tribal elders (community representatives). The process is ecclesiastical, military, and civic simultaneously — no single party controls the distribution.</p>",
    "2": "<p><em>bĕgôrāl naḥălātām kāʾašer ṣiwwāh YHWH bĕyad-mōšeh</em> — 'by lot was their inheritance, as YHWH commanded through Moses.' The <em>gôrāl</em> (lot) is the divine decision-mechanism that removes human favoritism from the distribution. Proverbs 16:33 theologically grounds this: 'The lot is cast into the lap, but every decision is from YHWH.' The lot is not a random procedure but an oracular one — YHWH assigns each tribe its place.</p>",
    "3": "<p>Moses had already given the two and a half trans-Jordan tribes their portions; Levi receives no land. The structured recapitulation (Levi noted here and in v.4b) is not redundancy but legal clarity: the nine and a half tribes' lots are about to begin; the exceptions are established first so the reader knows the scope of what follows.</p>",
    "4": "<p><em>kî-hāyû bĕnê yôsēp šĕnê maṭṭôt mĕnaššeh wĕʾeprayim</em> — 'for the sons of Joseph were two tribes, Manasseh and Ephraim.' The Joseph division is the mechanism by which twelve tribal lots fill twelve land portions despite Levi's exclusion. Jacob's deathbed elevation of Ephraim and Manasseh to tribal status (Gen 48:5: 'they shall be mine... as Reuben and Simeon they shall be mine') is the legal basis for this arithmetic. The Levitical cities and pasture lands (v.4b) are distinct from tribal allotments — Levi's distributed presence throughout the land embodies the nation's priestly calling.</p>",
    "5": "<p><em>kaʾašer ṣiwwāh YHWH ʾet-mōšeh kēn ʿāśû bĕnê yiśrāʾēl wayyaḥlĕqû ʾet-hāʾāreṣ</em> — 'as YHWH commanded Moses, so the Israelites did, and they divided the land.' The obedience formula closes the introduction and opens the Caleb narrative. The allotment process is an act of covenant obedience, not administrative convenience.</p>",
    "6": "<p><em>wayyiggĕšû bĕnê yĕhûdāh ʾel-yĕhôšuaʿ bĕgilgāl wayyōʾmer ʾēlāyw kālēb ben-yĕpunneh haqqĕnizzî</em> — 'the men of Judah approached Joshua at Gilgal, and Caleb son of Jephunneh the Kenizzite said to him.' Caleb the Kenizzite is a non-Israelite by ancestry (the Kenizzites are listed in Gen 15:19 among the peoples of the land) who is fully incorporated into Judah. His access to the allotment as a full heir demonstrates that covenant membership — not ethnic lineage — determines inheritance rights. The appeal to 'what YHWH said to Moses' (<em>ʾet-ʾašer dibber YHWH ʾel-mōšeh</em>) grounds his claim in prophetic promise, not merely military service.</p>",
    "7": "<p><em>ben-ʾarbaʿîm šānāh ʾānōkî bišloaḥ mōšeh ʿebed YHWH ʾōtî</em> — 'I was forty years old when Moses the servant of the LORD sent me.' The age specificity (forty at the reconnaissance, eighty-five now, v.10) structures the narrative: forty-five years from promise to fulfilment. Caleb's report: <em>kaʾašer ʿim-lĕbābî</em> — 'just as it was in my heart,' meaning the report he gave was his genuine conviction, not diplomatic accommodation. The <em>ʾăšer ʿim-lĕbābî</em> phrase connects sincerity of report with sincerity of faith.</p>",
    "8": "<p><em>wĕʾaḥay ʾašer ʿālû ʿimmî himmasîû ʾet-lēb hāʿām wĕʾānōkî millēʾtî ʾaḥărê YHWH ʾĕlōhāy</em> — 'my fellow scouts made the heart of the people melt, but I fully followed after YHWH my God.' The key verb: <em>millēʾtî</em> from <em>mālaʾ</em> (be full, fill) + <em>ʾaḥărê</em> (after, behind). <em>Millēʾ ʾaḥărê YHWH</em> is the book's distinctive idiom for wholehearted covenantal loyalty — used of Caleb in Num 14:24; 32:12; Deut 1:36; here and in vv.9,14. The idiom images following as 'filling the space behind' YHWH — not reluctant compliance but total engagement of will.</p>",
    "9": "<p><em>wayyiššābaʿ mōšeh bayyôm hahûʾ lēʾmōr ʾim-lōʾ hāʾāreṣ ʾašer dārakāh raglĕkā bāh lĕkā tihyeh lĕnaḥălāh</em> — 'Moses swore on that day: the land where your feet have walked shall be your inheritance.' The oath grounds Caleb's claim in prophetic promise (Num 14:24; Deut 1:36) ratified by Mosaic oath. Forty-five years of waiting has not diminished the claim; the oath remains binding because it was sworn before YHWH.</p>",
    "10": "<p><em>wĕʿattāh hinnēh heḥěyāh YHWH ʾōtî kaʾašer dibber</em> — 'now, look — YHWH has kept me alive just as he promised.' <em>Heḥěyāh</em> (kept alive, from <em>ḥāyāh</em>) is the same verb used of YHWH preserving life through the wilderness; Caleb attributes his forty-five-year survival not to constitution but to divine faithfulness. <em>mizzeh ʾarbaʿîm wĕḥāmēš šānāh</em> — forty-five years since the Sinai promise, twenty-five of which were conquest campaigns. The arithmetic of grace: the promise was made; the time has passed; YHWH has delivered.</p>",
    "11": "<p><em>kōḥî ʿōdennû hayyôm kaʾašer kōḥî bĕyôm šĕloaḥ mōšeh ʾōtî</em> — 'my strength today is still as my strength was on the day Moses sent me.' The claim is remarkable: eighty-five years old, and Caleb asserts physical parity with his forty-year-old self. Whether read literally (YHWH's supernatural preservation) or rhetorically (relative vigor, not comparative measurement), the statement is a theology of divine sustenance — Caleb's vitality is evidence of YHWH's faithfulness to his promise.</p>",
    "12": "<p><em>wĕʿattāh tĕnāh-lî ʾet-hāhār hazzeh</em> — 'now give me this hill country!' The imperative is bold — Caleb is not requesting but claiming. <em>Hāhār hazzeh</em> ('this hill country') is Hebron and its Anakite-held heights. Caleb had seen the Anakites and was unafraid at Kadesh (Num 13:33); now at eighty-five he asks for the hardest territory, the place where the giants live. <em>ûlay YHWH ʾittî wĕhôraštîm kaʾašer dibber YHWH</em> — 'perhaps YHWH will be with me, and I shall drive them out just as YHWH has said.' The <em>ûlay</em> ('perhaps, maybe') is not doubt but covenantal humility — Caleb frames the conquest as contingent on divine presence, not guaranteed by his vigor.</p>",
    "13": "<p><em>waybārekhēhû yĕhôšuaʿ wayyittēn ʾet-ḥebrôn lĕkālēb ben-yĕpunneh lĕnaḥălāh</em> — 'Joshua blessed him and gave Hebron to Caleb son of Jephunneh as inheritance.' The priestly blessing (<em>bārak</em>) before the grant marks this as a covenant act, not merely an administrative transfer. Hebron — Kiriath-arba, the city of Arba the greatest of the Anakites — is given to the man who was fearless before Anakites forty-five years earlier. Promise and fulfillment are calibrated: the specific fear that disqualified the first generation is overcome by the specific faith of the one who refused to fear.</p>",
    "14": "<p><em>ʿal-kēn hāyĕtāh ḥebrôn lĕkālēb ben-yĕpunneh haqqĕnizzî lĕnaḥălāh ʿad hayyôm hazzeh yaʿan ʾašer millēʾ ʾaḥărê YHWH ʾĕlōhê yiśrāʾēl</em> — 'therefore Hebron has belonged to Caleb son of Jephunneh the Kenizzite as inheritance to this day, because he wholeheartedly followed YHWH God of Israel.' The causal chain is explicit: the inheritance is the consequence of wholehearted following. <em>Millēʾ ʾaḥărê YHWH</em> (appearing for the final time) is the book's summary verdict on Caleb's life: one who filled the space behind YHWH completely. The 'to this day' formula anchors the etiological claim — Hebron as Calebite territory is a historical fact requiring explanation, and the explanation is theological.</p>",
    "15": "<p><em>wĕšem ḥebrôn lĕpānîm qiryat-ʾarbaʿ</em> — 'the former name of Hebron was Kiriath-arba.' The rename from 'city of Arba' (the greatest Anakite) to 'Hebron' (from <em>ḥābar</em>, 'friend/confederate') may reflect Hebrew renaming practice after conquest. Arba's name and greatness are preserved even in the record of his people's defeat — the text does not erase the enemy's memory but notes it within the victory account. <em>Wattišqōt hāʾāreṣ mimmilḥāmāh</em> — 'and the land had rest from war.' The <em>šāqaṭ</em> (rest/quiet) formula closes this section as it closed ch.11:23; each major phase of the narrative ends with land-rest as the theological verdict: YHWH's wars, when completed, produce peace.</p>"
  }
}


def main():
    existing = load_comm('mkt-original', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('mkt-original', 'joshua', existing)

    il = json.loads((ROOT / 'data/interlinear/joshua.json').read_text())
    all_ok = True
    for ch in range(12, 15):
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present ✓')


if __name__ == '__main__':
    main()
